fn build_evm_with_pool(self, ctx: &BuilderContext<Node>, pool: impl TransactionPoolExt + Clone + 'static) -> ... {
    let block_verifier = Arc::new(BlockVerifier::new_with_evm_classification(
        pool.clone(), ctx.provider().clone(), evm_config.clone(), None,
    ));
    let ritual_executor = RitualBlockExecutorProvider::new(
        evm_config.clone(), spc_verifier, Some(block_verifier),
    );
}
